<?php if($isTeacher):?>
<div class="metrics teacher-summary" aria-label="Resumo dos meus relatórios"><article class="metric static status-card-devolvido"><span class="metric-label">Precisam da sua ação</span><strong><?=count($needsAction)?></strong><small>Pendentes, rascunhos ou devolvidos</small></article><article class="metric static status-card-enviado"><span class="metric-label">Já enviados</span><strong><?=count($alreadySent)?></strong><small>Na coordenação ou aprovados</small></article><article class="metric static"><span class="metric-label">Total de turmas</span><strong><?=count($reports)?></strong><small>Relatórios atribuídos a você</small></article></div>
<section class="card work-list priority-list"><div class="section-heading"><div><p class="eyebrow">Prioridade</p><h2>Turmas que precisam de preenchimento</h2><p><?=count($needsAction)?> relatório(s) aguardando sua ação</p></div><?php if($needsAction):?><label class="search"><span class="sr-only">Buscar turma pendente</span><span aria-hidden="true">⌕</span><input type="search" placeholder="Buscar turma ou disciplina" data-table-search="#teacher-pending"></label><?php endif;?></div><?php if(!$needsAction):?><div class="empty-state compact"><span aria-hidden="true">✓</span><h3>Tudo em dia</h3><p>Você não possui relatórios aguardando preenchimento ou correção.</p></div><?php else:?><div class="table"><table id="teacher-pending"><thead><tr><th>Turma e disciplina</th><th>Período</th><th>Situação</th><th>Prazo</th><th><span class="sr-only">Ação</span></th></tr></thead><tbody><?php $renderTeacherRows($needsAction);?></tbody></table></div><?php endif;?></section>
<section class="card work-list"><div class="section-heading"><div><p class="eyebrow">Acompanhamento</p><h2>Relatórios que você já enviou</h2><p><?=count($alreadySent)?> relatório(s) enviado(s)</p></div><?php if($alreadySent):?><label class="search"><span class="sr-only">Buscar relatório enviado</span><span aria-hidden="true">⌕</span><input type="search" placeholder="Buscar turma ou disciplina" data-table-search="#teacher-sent"></label><?php endif;?></div><?php if(!$alreadySent):?><div class="empty-state compact"><p>Nenhum relatório foi enviado ainda.</p></div><?php else:?><div class="table"><table id="teacher-sent"><thead><tr><th>Turma e disciplina</th><th>Período</th><th>Situação</th><th>Prazo</th><th><span class="sr-only">Ação</span></th></tr></thead><tbody><?php $renderTeacherRows($alreadySent);?></tbody></table></div><?php endif;?></section>
<?php else:$notFinished=$counts['PENDENTE']+$counts['RASCUNHO']+$counts['DEVOLVIDO'];?>
