<section class="card work-list"><div class="section-heading"><div><p class="eyebrow">Acompanhamento da equipe</p><h2>Situação por professor</h2><p><?=count($professorProgress)?> professor(es) com relatórios</p></div><?php if($professorProgress):?><label class="search"><span class="sr-only">Buscar professor ou turma</span><span aria-hidden="true">⌕</span><input id="professor-search" type="search" placeholder="Buscar professor, turma ou disciplina"></label><?php endif;?></div>
<?php if(!$professorProgress):?><div class="empty-state"><span aria-hidden="true">✓</span><h3>Nenhum relatório gerado</h3><p>Os professores aparecerão após a abertura de um período com vínculos ativos.</p></div><?php else:?><div class="professor-list"><?php foreach($professorProgress as$p):$allDone=$p['pendentes']===0&&$p['enviados']===0;$nothingSent=$p['enviados']===0&&$p['aprovados']===0;$state=$allDone?'Concluído':($nothingSent?'Ainda não enviou':($p['pendentes']>0?'Envio parcial':'Aguardando conferência'));$stateClass=$allDone?'aprovado':($nothingSent?'devolvido':($p['pendentes']>0?'rascunho':'enviado'));?><details class="professor-card" <?=($p['pendentes']>0||$p['enviados']>0)?'open':''?>><summary><span class="professor-identity"><span class="avatar" aria-hidden="true"><?=e(mb_strtoupper(mb_substr($p['nome'],0,1)))?></span><span><strong><?=e($p['nome'])?></strong><small><?=e($p['total'])?> relatório(s) · <?=e($p['pendentes'])?> não concluído(s) · <?=e($p['enviados'])?> para conferir</small></span></span><span class="badge status-<?=e($stateClass)?>"><?=e($state)?></span></summary><div class="table"><table><thead><tr><th>Turma e disciplina</th><th>Período</th><th>Situação</th><th>Prazo</th><th><span class="sr-only">Ação</span></th></tr></thead><tbody><?php foreach($p['reports'] as$r):?><tr><td data-label="Turma e disciplina"><strong><?=e($r['turma_nome_snapshot'])?></strong><small><?=e($r['disciplina'])?></small></td><td data-label="Período"><?=e($r['periodo'])?></td><td data-label="Situação"><span class="badge status-<?=e(strtolower($r['status']))?>"><?=e($labels[$r['status']]??$r['status'])?></span></td><td data-label="Prazo"><?=e(date('d/m/Y',strtotime($r['data_fim'])))?></td><td class="row-action"><a class="button <?=$r['status']==='ENVIADO'?'primary':''?>" href="/relatorios/<?=e($r['id'])?>"><?=$r['status']==='ENVIADO'?'Conferir':'Visualizar'?> <span aria-hidden="true">→</span></a></td></tr><?php endforeach;?></tbody></table></div></details><?php endforeach;?></div><div id="professor-empty" class="empty-state compact" hidden><p>Nenhum professor corresponde à busca.</p></div><?php endif;?></section><?php endif;?><?php $content=ob_get_clean();require __DIR__.'/layout.php';
